Deserializing untrusted data without proper validation is a critical security vulnerability. While Go's `encoding/json` package is safer than some languages' serialization (like Java's ObjectInputStream), misconfigurations can still lead to serious issues including resource exhaustion, type confusion, and injection attacks.

**VULNERABLE CODE**:

```go
package main

import (
	"encoding/json"
	"io/ioutil"
	"net/http"
)

type UserConfig struct {
	Username    string                 `json:"username"`
	Permissions []string               `json:"permissions"`
	Settings    map[string]interface{} `json:"settings"`
	Metadata    interface{}            `json:"metadata"`
}

func handleConfig(w http.ResponseWriter, r *http.Request) {
	// VULNERABLE: No size limit on request body
	body, _ := ioutil.ReadAll(r.Body)
	defer r.Body.Close()

	var config UserConfig
	// VULNERABLE: Deserializing into interface{} allows arbitrary structures
	if err := json.Unmarshal(body, &config); err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	// VULNERABLE: No validation of deserialized data
	// Attacker can inject arbitrary permissions or settings
	updateUserConfig(config)

	w.WriteHeader(http.StatusOK)
}

func updateUserConfig(config UserConfig) {
	// Processes config without validation
}

func main() {
	http.HandleFunc("/config", handleConfig)
	http.ListenAndServe(":8080", nil)
}
```

**Attack Payload**:
```json
{
  "username": "attacker",
  "permissions": ["admin", "superuser", "root"],
  "settings": {
    "__proto__": {"isAdmin": true},
    "nestedObject": {"very": {"deep": {"nesting": {"repeating": "infinitely"}}}}
  },
  "metadata": [[[[[[[[[[[[[[[[[[[[[[[[[[]]]]]]]]]]]]]]]]]]]]]]]]]
