**Why This Is Dangerous**:
- No request body size limit allows memory exhaustion attacks (CVE-like DoS)
- Using `interface{}` types allows arbitrary data structures
- No validation of deserialized content enables privilege escalation
- Deeply nested structures can cause stack overflow or high CPU usage
- Error messages leak internal structure information

**SECURE VERSION**:

```go
package main

import (
	"encoding/json"
	"io"
	"log"
	"net/http"
	"regexp"
)

const (
	MaxBodySize     = 1024 * 1024 // 1MB max
	MaxNestingDepth = 10
)

var validUsername = regexp.MustCompile(`^[a-zA-Z0-9_]{3,32}$`)
var allowedPermissions = map[string]bool{
	"read": true, "write": true, "delete": false,
}

// SECURE: Strict typed struct with explicit fields
type SecureUserConfig struct {
	Username    string            `json:"username"`
	Permissions []string          `json:"permissions"`
	Settings    UserSettings      `json:"settings"`
}

type UserSettings struct {
	Theme        string `json:"theme"`
	Notifications bool   `json:"notifications"`
}

func handleConfigSecure(w http.ResponseWriter, r *http.Request) {
	// SECURE: Limit request body size
	r.Body = http.MaxBytesReader(w, r.Body, MaxBodySize)

	// SECURE: Use json.Decoder with strict settings
	decoder := json.NewDecoder(r.Body)
	decoder.DisallowUnknownFields() // Reject unexpected fields

	var config SecureUserConfig
	if err := decoder.Decode(&config); err != nil {
		log.Printf("JSON decode error from %s: %v", r.RemoteAddr, err)
		http.Error(w, "Invalid request format", http.StatusBadRequest)
		return
	}

	// SECURE: Validate all deserialized data
	if err := validateConfig(&config); err != nil {
		log.Printf("Validation failed from %s: %v", r.RemoteAddr, err)
		http.Error(w, "Validation failed", http.StatusBadRequest)
		return
	}

	updateUserConfigSecure(config)
	w.WriteHeader(http.StatusOK)
}

func validateConfig(config *SecureUserConfig) error {
	if !validUsername.MatchString(config.Username) {
		return fmt.Errorf("invalid username format")
	}

	for _, perm := range config.Permissions {
		if !allowedPermissions[perm] {
			return fmt.Errorf("invalid permission: %s", perm)
		}
	}

	return nil
