addFormats(ajv);

// Structured logging
const logger = winston.createLogger({
    level: 'info',
    format: winston.format.json(),
    transports: [
        new winston.transports.File({ filename: 'security.log' })
    ]
});

// Strict JSON schema for complex session data
const complexSessionSchema = {
    type: 'object',
    required: ['userId', 'permissions', 'metadata'],
    additionalProperties: false,
    properties: {
        userId: { type: 'string', format: 'uuid' },
        permissions: {
            type: 'array',
            maxItems: 50,
            items: {
                type: 'object',
                required: ['resource', 'actions'],
                additionalProperties: false,
                properties: {
                    resource: { type: 'string', pattern: '^[a-z_]{1,50}$' },
                    actions: {
                        type: 'array',
                        items: { type: 'string', enum: ['read', 'write', 'delete', 'admin'] },
                        maxItems: 4
                    }
                }
            }
        },
        metadata: {
            type: 'object',
            additionalProperties: false,
            properties: {
                theme: { type: 'string', enum: ['light', 'dark', 'system'] },
                language: { type: 'string', pattern: '^[a-z]{2}(-[A-Z]{2})?$' },
                lastActivity: { type: 'string', format: 'date-time' }
            }
        }
    }
};

const validateSession = ajv.compile(complexSessionSchema);

class SafeSessionManager {
    constructor(redis, logger) {
        this.redis = redis;
        this.logger = logger;
        this.SESSION_TTL = 3600; // 1 hour
    }

    // Generate secure session ID
    generateSessionId() {
        return crypto.randomBytes(32).toString('hex');
    }

    // SECURE: Store complex data server-side, only send opaque token to client
    async createSession(userId, permissions, metadata, requestContext) {
        const sessionId = this.generateSessionId();
        const sessionData = {
            userId,
            permissions,
            metadata,
            createdAt: new Date().toISOString(),
            userAgent: requestContext.userAgent,
            ipAddress: requestContext.ip
        };

        // Validate before storing
        if (!validateSession(sessionData)) {
            this.logger.error('Invalid session data structure', {
                errors: validateSession.errors,
                userId
            });
            throw new Error('Invalid session data');
        }

        // Store as JSON string in Redis (no code execution possible)
        await this.redis.setex(
            `session:${sessionId}`,
            this.SESSION_TTL,
            JSON.stringify(sessionData)
        );

        // Audit log
        this.logger.info('Session created', {
            sessionId: sessionId.substring(0, 8) + '...',
            userId,
            ip: requestContext.ip
        });

        return sessionId;
    }

    // SECURE: Safe deserialization with JSON.parse and validation
    async getSession(sessionId, requestContext) {
        // Validate session ID format first
        if (!/^[a-f0-9]{64}$/.test(sessionId)) {
            this.logger.warn('Invalid session ID format', {
                ip: requestContext.ip
            });
            return null;
        }

        const rawData = await this.redis.get(`session:${sessionId}`);
        if (!rawData) {
            return null;
        }

        let sessionData;
        try {
            // SAFE: JSON.parse does NOT execute code
            sessionData = JSON.parse(rawData);
        } catch (parseError) {
            this.logger.error('Session data corruption', {
                sessionId: sessionId.substring(0, 8) + '...',
                error: parseError.message
            });
            await this.redis.del(`session:${sessionId}`);
            return null;
        }

        // Re-validate after parsing (defense in depth)
        if (!validateSession(sessionData)) {
            this.logger.error('Session validation failed', {
                sessionId: sessionId.substring(0, 8) + '...',
                errors: validateSession.errors
            });
            await this.redis.del(`session:${sessionId}`);
            return null;
        }

        // Session binding check
        if (sessionData.userAgent !== requestContext.userAgent) {
            this.logger.warn('Session hijacking attempt detected', {
                sessionId: sessionId.substring(0, 8) + '...',
                expectedUA: sessionData.userAgent,
                actualUA: requestContext.userAgent,
                ip: requestContext.ip
            });
            return null;
        }

        // Refresh TTL on access
        await this.redis.expire(`session:${sessionId}`, this.SESSION_TTL);

        return sessionData;
    }

    async destroySession(sessionId) {
        await this.redis.del(`session:${sessionId}`);
    }
}

