    }

    res.json({
        userId: req.session.userId,
        permissions: req.session.permissions,
        metadata: req.session.metadata
    });
});

app.listen(3000);
```

**Defense in Depth Layers**:

1. **Never deserialize untrusted data with eval-based libraries**:
```javascript
